text:
{
  "formal_minutes": {
    "decisions": [
      {
        "type": "확정 의사결정",
        "item": "스모크 테스트가 통과할 경우 공개 릴리스는 금요일 15:00 KST로 결정한다."
      },
      {
        "type": "확정 의사결정",
        "item": "packageName 불일치 발생 시, smoke-theme-pack.mjs를 무시하는 방식으로 처리하지 않는다. 우선 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      },
      {
        "type": "확정 액션",
        "item": "Minjun이 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다."
      },
      {
        "type": "확정 액션",
        "item": "Doyun이 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다."
      }
    ],
    "non_decisions": [
      {
        "type": "rejected_proposal",
        "item": "Hara가 제안한 smoke-theme-pack.mjs의 packageName 불일치 무시 제안은 거부되었다.",
        "reason": "문제의 원인 추적을 위해 계약/패키지 설정 검증 우선 원칙을 유지"
      },
      {
        "type": "internal_stretch_goal",
        "item": "수요일 공개 릴리스는 내부 스트레치 목표로만 간주하며, 최종 공개 일정으로 확정되지 않았다."
      },
      {
        "type": "미해결 과제",
        "item": "README 설치 단계 검토의 주체(Owner)는 지정되지 않았고, 기한도 정확히 확정되지 않았다."
      },
      {
        "type": "미해결 과제",
        "item": "Hara의 tarball 경로 확인은 Minjun 결과 공유 후 진행되며, 정확한 최종 기한은 미정이다."
      }
    ],
    "risks": [
      "잘못된 tarball 경로가 있을 경우 릴리스가 지연될 수 있다.",
      "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 기재할지 여부는 미결정이다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성 tarball 경로 확인",
      "due": "Minjun 결과 공유 후",
      "status": "확정",
      "source_certainty": "중간"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목요일 가능 시",
      "status": "진행 필요",
      "source_certainty": "높음"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 전 Minjun의 스모크 재실행 결과 수집",
      "결과를 바탕으로 금요일 15:00 KST 공개 가능성 판단",
      "Doyun 작성 트리아지 노트 제출 여부 확인",
      "Hara의 tarball 경로 확인 수행 여부 확인",
      "README 최신성 검토 후 릴리스 노트 반영 여부 협의"
    ],
    "what_not_to_invent": [
      "고객명/파트너명",
      "예산 수치 또는 예산 승인 여부",
      "보안 사고·보안 인시던트 관련 사실",
      "운영 장애 발생 여부",
      "법적 승인 요건 관련 사실",
      "노트에 없는 특정 owner/마감일(명시되지 않은 항목)"
    ]
  },
  "non_invention_rules": [
    "노트에 없는 고객/예산/보안/아웃티지/법적 승인 요구/외부 의사결정자의 실체를 추가하지 않는다.",
    "시간은 본문에 명시된 ‘금요일 10:00 KST, 금요일 12:00 KST, 금요일 15:00 KST, 목요일 가능 시’ 수준으로만 기재하고 임의의 절대 날짜를 추가하지 않는다.",
    "소유자가 미지정으로 언급된 항목은 임의로 배정하지 않는다.",
    "제안이 거절된 사실(예: packageName 불일치 무시)은 거절로 유지하고 통과 처리하지 않는다.",
    "릴리스일/노트 항목의 미결정 사안은 ‘미결정’으로 유지한다."
  ]
}
